/* =====================================================================
   AURA ALPHA — TradingView Webhooks
   Manage webhook API keys, view events, test webhooks, and see setup
   instructions for connecting TradingView alerts to paper trading.
   ===================================================================== */
import { useState, useEffect, useRef, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import AnimatedPage from '../components/AnimatedPage';
import usePageTitle from '../hooks/usePageTitle';
import useIsMobile from '../hooks/useIsMobile';
import { api, apiPost, apiDelete } from '../utils/api';
import { tokens } from '../styles/tokens';
import s from './WebhooksPage.module.css';

// -- Design tokens -----------------------------------------------------------
const C = {
  bg: tokens.color.bg, surface: tokens.color.surface, surface2: tokens.color.surfaceHover,
  border: tokens.color.border, textPrimary: tokens.color.text, textSecondary: tokens.color.textSecondary,
  green: tokens.color.green, red: tokens.color.red, blue: tokens.color.blue,
  amber: tokens.color.amber, purple: tokens.color.purple,
};

const WEBHOOK_URL = 'https://auraalpha.cc/api/webhooks/tradingview';

// -- Helpers -----------------------------------------------------------------
const fmtTime = (ts) => {
  if (!ts) return '--';
  try {
    const d = new Date(ts);
    if (isNaN(d.getTime())) return ts;
    return d.toLocaleString('en-US', {
      month: 'short', day: 'numeric',
      hour: '2-digit', minute: '2-digit', hour12: false,
    });
  } catch { return ts; }
};

const statusColor = (st) => {
  if (!st) return C.textSecondary;
  const sl = st.toLowerCase();
  if (sl === 'filled' || sl === 'submitted') return C.green;
  if (sl === 'error' || sl === 'rate_limited') return C.red;
  if (sl === 'test') return C.purple;
  if (sl === 'skipped') return C.amber;
  return C.textSecondary;
};

// -- GlassPanel --------------------------------------------------------------
function GlassPanel({ children, className = '', style }) {
  return (
    <div className={`${s.glassPanel} ${className}`} style={style}>
      {children}
    </div>
  );
}

// -- Section header ----------------------------------------------------------
function SectionHeader({ title, sub }) {
  return (
    <div className={s.sectionHeaderWrap}>
      <div className={s.sectionHeaderTitle}>{title}</div>
      {sub && <div className={s.sectionHeaderSub}>{sub}</div>}
    </div>
  );
}

// -- Pill button -------------------------------------------------------------
function PillBtn({ label, onClick, color = C.blue, disabled, loading: btnLoading, small }) {
  return (
    <motion.button
      whileTap={{ scale: 0.97 }}
      onClick={onClick}
      disabled={disabled || btnLoading}
      className={`${s.pillBtn} ${small ? s.pillBtnSmall : s.pillBtnNormal} ${disabled ? s.pillBtnDisabled : ''}`}
      style={{ background: color }}
    >
      {btnLoading ? 'Working...' : label}
    </motion.button>
  );
}

// -- Tab button --------------------------------------------------------------
function TabBtn({ label, active, onClick }) {
  return (
    <motion.button
      whileTap={{ scale: 0.97 }}
      onClick={onClick}
      className={`${s.tabBtn} ${active ? s.tabBtnActive : s.tabBtnInactive}`}
    >
      {label}
    </motion.button>
  );
}

// -- Table header / data cells -----------------------------------------------
function TH({ children, align = 'left' }) {
  return (
    <th className={s.th} style={{ textAlign: align }}>
      {children}
    </th>
  );
}

function TD({ children, color = C.textPrimary, align = 'left', useMono = false, style: extra }) {
  return (
    <td
      className={`${s.td} ${useMono ? s.tdMono : s.tdBody}`}
      style={{ color, textAlign: align, ...extra }}
    >
      {children}
    </td>
  );
}

// -- Copyable URL / text -----------------------------------------------------
function CopyField({ label, value, isMobile }) {
  const [copied, setCopied] = useState(false);

  const handleCopy = () => {
    navigator.clipboard.writeText(value).then(() => {
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    });
  };

  return (
    <div className={s.copyFieldWrap}>
      {label && <div className={s.copyFieldLabel}>{label}</div>}
      <div className={s.copyFieldRow}>
        <code className={`${s.copyFieldCode} ${isMobile ? s.copyFieldCodeMobile : s.copyFieldCodeDesktop}`}>
          {value}
        </code>
        <motion.button
          whileTap={{ scale: 0.9 }}
          onClick={handleCopy}
          className={`${s.copyBtn} ${copied ? s.copyBtnCopied : s.copyBtnDefault}`}
        >
          {copied ? 'Copied' : 'Copy'}
        </motion.button>
      </div>
    </div>
  );
}

// -- Code block --------------------------------------------------------------
function CodeBlock({ code, isMobile }) {
  const [copied, setCopied] = useState(false);

  const handleCopy = () => {
    navigator.clipboard.writeText(code).then(() => {
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    });
  };

  return (
    <div className={s.codeBlockWrap}>
      <pre className={`${s.codeBlockPre} ${isMobile ? s.codeBlockPreMobile : s.codeBlockPreDesktop}`}>
        {code}
      </pre>
      <motion.button
        whileTap={{ scale: 0.9 }}
        onClick={handleCopy}
        className={`${s.codeBlockCopyBtn} ${copied ? s.codeBlockCopyCopied : s.codeBlockCopyDefault}`}
      >
        {copied ? 'Copied' : 'Copy'}
      </motion.button>
    </div>
  );
}


// ============================================================================
// MAIN COMPONENT
// ============================================================================
export default function WebhooksPage() {
  usePageTitle('Webhooks');
  const isMobile = useIsMobile();

  // -- State -----------------------------------------------------------------
  const [tab, setTab] = useState('setup');
  const [keys, setKeys] = useState([]);
  const [events, setEvents] = useState([]);
  const [loading, setLoading] = useState(true);
  const [keyLabel, setKeyLabel] = useState('');
  const [creating, setCreating] = useState(false);
  const [newKey, setNewKey] = useState(null);
  const [revoking, setRevoking] = useState(null);
  const [msg, setMsg] = useState(null);

  // Test webhook state
  const [testAction, setTestAction] = useState('buy');
  const [testSymbol, setTestSymbol] = useState('AAPL');
  const [testPrice, setTestPrice] = useState('150.00');
  const [testQty, setTestQty] = useState('10');
  const [testStrategy, setTestStrategy] = useState('My TradingView Strategy');
  const [testTimeframe, setTestTimeframe] = useState('1H');
  const [testResult, setTestResult] = useState(null);
  const [testing, setTesting] = useState(false);

  const abortRef = useRef(null);

  // -- Data fetching ---------------------------------------------------------
  const fetchKeys = useCallback(async (signal) => {
    const data = await api('/webhooks/keys', { signal, silent: true });
    if (data?.keys) setKeys(data.keys);
  }, []);

  const fetchEvents = useCallback(async (signal) => {
    const data = await api('/webhooks/events?limit=50', { signal, silent: true });
    if (data?.events) setEvents(data.events);
  }, []);

  useEffect(() => {
    const ac = new AbortController();
    abortRef.current = ac;

    async function loadAll() {
      setLoading(true);
      await Promise.all([fetchKeys(ac.signal), fetchEvents(ac.signal)]);
      setLoading(false);
    }
    loadAll();

    // Poll events every 15s
    const iv = setInterval(() => {
      if (!ac.signal.aborted) fetchEvents(ac.signal);
    }, 15000);

    return () => { ac.abort(); clearInterval(iv); };
  }, [fetchKeys, fetchEvents]);

  // -- Actions ---------------------------------------------------------------
  const handleCreateKey = async () => {
    setCreating(true);
    setMsg(null);
    setNewKey(null);
    const data = await apiPost('/webhooks/keys', { label: keyLabel.trim() });
    if (data?.key) {
      setNewKey(data.key);
      setKeyLabel('');
      fetchKeys(abortRef.current?.signal);
      setMsg({ type: 'ok', text: 'API key created. Copy and save it securely.' });
    } else {
      setMsg({ type: 'error', text: 'Failed to create key' });
    }
    setCreating(false);
  };

  const handleRevokeKey = async (keyId) => {
    setRevoking(keyId);
    const data = await apiDelete(`/webhooks/keys/${keyId}`);
    if (data?.status === 'revoked') {
      setMsg({ type: 'ok', text: 'Key revoked successfully' });
      fetchKeys(abortRef.current?.signal);
    } else {
      setMsg({ type: 'error', text: 'Failed to revoke key' });
    }
    setRevoking(null);
  };

  const handleTest = async () => {
    const activeKey = keys.find(k => k.active);
    if (!activeKey) {
      setTestResult({ valid: false, errors: ['No active webhook key. Create one first.'] });
      return;
    }

    setTesting(true);
    setTestResult(null);
    const payload = {
      action: testAction,
      symbol: testSymbol.toUpperCase(),
      price: parseFloat(testPrice) || 0,
      quantity: parseInt(testQty, 10) || 0,
      strategy: testStrategy,
      timeframe: testTimeframe,
      key: 'YOUR_KEY_HERE',
    };

    // We use the test endpoint through our API (which adds auth headers)
    const data = await apiPost('/webhooks/tradingview/test', payload);
    if (data) {
      setTestResult(data);
      // Refresh events
      setTimeout(() => fetchEvents(abortRef.current?.signal), 500);
    } else {
      setTestResult({ valid: false, errors: ['Request failed. Check console.'] });
    }
    setTesting(false);
  };

  // -- Layout ----------------------------------------------------------------
  const pad = isMobile ? 16 : 28;

  return (
    <AnimatedPage>
      <div className={`${s.pageRoot} ${isMobile ? s.pageRootMobile : s.pageRootDesktop}`}>
        {/* Header */}
        <div className={s.headerSection}>
          <h1 className={`${s.headerTitle} ${isMobile ? s.headerTitleMobile : s.headerTitleDesktop}`}>
            TradingView Webhooks
          </h1>
          <p className={s.headerSub}>
            Connect TradingView alerts to your Aura Alpha paper trading account.
            When an alert fires, TradingView sends a POST request that automatically executes trades.
          </p>
        </div>

        {/* Tabs */}
        <div className={s.tabRow}>
          <TabBtn label="Setup" active={tab === 'setup'} onClick={() => setTab('setup')} />
          <TabBtn label="API Keys" active={tab === 'keys'} onClick={() => setTab('keys')} />
          <TabBtn label="Events" active={tab === 'events'} onClick={() => setTab('events')} />
          <TabBtn label="Test" active={tab === 'test'} onClick={() => setTab('test')} />
        </div>

        {/* Toast */}
        <AnimatePresence>
          {msg && (
            <motion.div
              initial={{ opacity: 0, y: -10 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, y: -10 }}
              className={`${s.toast} ${msg.type === 'ok' ? s.toastOk : s.toastError}`}
            >
              {msg.text}
            </motion.div>
          )}
        </AnimatePresence>

        {/* ============================================================= */}
        {/* SETUP TAB */}
        {/* ============================================================= */}
        {tab === 'setup' && (
          <div>
            <GlassPanel style={{ padding: pad }}>
              <SectionHeader
                title="How It Works"
                sub="TradingView alerts send a POST request with a JSON body to your webhook URL. Aura Alpha authenticates via your API key and routes the trade to paper trading."
              />

              <div className={`${s.stepGrid} ${isMobile ? s.stepGridMobile : s.stepGridDesktop}`}>
                {[
                  { step: '1', title: 'Generate API Key', desc: 'Create a key in the API Keys tab. Copy it.' },
                  { step: '2', title: 'Create TradingView Alert', desc: 'Set webhook URL and paste JSON template with your key.' },
                  { step: '3', title: 'Receive Trades', desc: 'When alerts fire, trades execute in your paper account.' },
                ].map(({ step, title, desc }) => (
                  <div key={step} className={s.stepCard}>
                    <div className={s.stepNum}>{step}</div>
                    <div className={s.stepTitle}>{title}</div>
                    <div className={s.stepDesc}>{desc}</div>
                  </div>
                ))}
              </div>

              <SectionHeader title="Webhook URL" sub="Set this as the Webhook URL in your TradingView alert settings." />
              <CopyField value={WEBHOOK_URL} isMobile={isMobile} />

              <div className={s.mt24}>
                <SectionHeader
                  title="Alert Message Template"
                  sub="In TradingView, set the alert message to this JSON. Replace YOUR_API_KEY with your actual key."
                />
                <CodeBlock
                  isMobile={isMobile}
                  code={`{
  "action": "{{strategy.order.action}}",
  "symbol": "{{ticker}}",
  "price": {{close}},
  "quantity": 10,
  "strategy": "{{strategy.order.comment}}",
  "timeframe": "{{interval}}",
  "key": "YOUR_API_KEY"
}`}
                />
              </div>

              <div className={s.mt24}>
                <SectionHeader
                  title="Manual Alert Template"
                  sub='For non-strategy alerts (e.g. price crossing MA), use literal values for action.'
                />
                <CodeBlock
                  isMobile={isMobile}
                  code={`{
  "action": "buy",
  "symbol": "AAPL",
  "price": {{close}},
  "quantity": 10,
  "strategy": "MA Crossover",
  "timeframe": "1H",
  "key": "YOUR_API_KEY"
}`}
                />
              </div>

              <div className={s.supportedActionsBox}>
                <div className={s.supportedActionsTitle}>Supported Actions</div>
                <div className={s.supportedActionsBody}>
                  <span className={s.actionBuy}>buy</span> &mdash; Open a long position (BUY order)<br />
                  <span className={s.actionSell}>sell</span> &mdash; Open a short position or sell existing (SELL order)<br />
                  <span className={s.actionClose}>close</span> &mdash; Close existing position (auto-detects direction)<br />
                </div>
              </div>

              <div className={s.rateLimitsBox}>
                <div className={s.rateLimitsTitle}>Rate Limits</div>
                <div className={s.rateLimitsBody}>
                  Maximum 60 webhooks per minute per API key. Exceeding this returns HTTP 429.
                  If quantity is omitted, a default of ~$1,000 worth at the alert price is used.
                </div>
              </div>
            </GlassPanel>
          </div>
        )}

        {/* ============================================================= */}
        {/* API KEYS TAB */}
        {/* ============================================================= */}
        {tab === 'keys' && (
          <div>
            {/* Create key form */}
            <GlassPanel className={s.mb20} style={{ padding: pad }}>
              <SectionHeader
                title="Create Webhook API Key"
                sub="Each key authenticates webhook requests. You can have up to 10 active keys."
              />
              <div className={`${s.createKeyForm} ${isMobile ? s.createKeyFormMobile : s.createKeyFormDesktop}`}>
                <div className={s.createKeyInputWrap}>
                  <label className={s.formLabel}>Label (optional)</label>
                  <input
                    type="text"
                    value={keyLabel}
                    onChange={e => setKeyLabel(e.target.value)}
                    placeholder="e.g. TradingView Main"
                    maxLength={50}
                    className={s.formInput}
                  />
                </div>
                <PillBtn
                  label="Generate Key"
                  onClick={handleCreateKey}
                  loading={creating}
                  disabled={creating}
                  color={C.green}
                />
              </div>

              {/* Show newly created key */}
              <AnimatePresence>
                {newKey && (
                  <motion.div
                    initial={{ opacity: 0, height: 0 }}
                    animate={{ opacity: 1, height: 'auto' }}
                    exit={{ opacity: 0, height: 0 }}
                    style={{ marginTop: 16, overflow: 'hidden' }}
                  >
                    <div className={s.newKeyBox}>
                      <div className={s.newKeyTitle}>
                        New Key Created — Copy it now (it will not be shown again in full)
                      </div>
                      <CopyField value={newKey.key} isMobile={isMobile} />
                    </div>
                  </motion.div>
                )}
              </AnimatePresence>
            </GlassPanel>

            {/* Keys table */}
            <GlassPanel style={{ padding: 0 }}>
              <div style={{ padding: `${pad}px ${pad}px 12px` }}>
                <SectionHeader title="Your API Keys" />
              </div>
              {loading ? (
                <div className={s.emptyState}>Loading...</div>
              ) : keys.length === 0 ? (
                <div className={s.emptyState}>No webhook keys yet. Create one above.</div>
              ) : (
                <div className={s.tableWrap}>
                  <table className={s.table}>
                    <thead>
                      <tr>
                        <TH>Key</TH>
                        <TH>Label</TH>
                        <TH>Status</TH>
                        <TH align="right">Uses</TH>
                        <TH>Created</TH>
                        <TH>Last Used</TH>
                        <TH align="center">Action</TH>
                      </tr>
                    </thead>
                    <tbody>
                      {keys.map(k => (
                        <tr key={k.id}>
                          <TD useMono>{k.key_masked}</TD>
                          <TD color={C.textSecondary}>{k.label || '--'}</TD>
                          <TD color={k.active ? C.green : C.red} useMono>
                            {k.active ? 'Active' : 'Revoked'}
                          </TD>
                          <TD align="right" useMono>{k.use_count}</TD>
                          <TD color={C.textSecondary}>{fmtTime(k.created_at)}</TD>
                          <TD color={C.textSecondary}>{fmtTime(k.last_used)}</TD>
                          <TD align="center">
                            {k.active && (
                              <PillBtn
                                label={revoking === k.id ? 'Revoking...' : 'Revoke'}
                                onClick={() => handleRevokeKey(k.id)}
                                color={C.red}
                                small
                                disabled={revoking === k.id}
                              />
                            )}
                          </TD>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              )}
            </GlassPanel>
          </div>
        )}

        {/* ============================================================= */}
        {/* EVENTS TAB */}
        {/* ============================================================= */}
        {tab === 'events' && (
          <GlassPanel style={{ padding: 0 }}>
            <div style={{ padding: `${pad}px ${pad}px 12px` }}>
              <SectionHeader
                title="Recent Webhook Events"
                sub="Audit log of all incoming webhook requests. Auto-refreshes every 15 seconds."
              />
            </div>
            {loading ? (
              <div className={s.emptyState}>Loading...</div>
            ) : events.length === 0 ? (
              <div className={s.emptyState}>
                No webhook events yet. Events appear here once alerts start firing.
              </div>
            ) : (
              <div className={s.tableWrap}>
                <table className={s.table}>
                  <thead>
                    <tr>
                      <TH>Time</TH>
                      <TH>Action</TH>
                      <TH>Symbol</TH>
                      <TH align="right">Qty</TH>
                      <TH align="right">Price</TH>
                      <TH>Strategy</TH>
                      <TH>Status</TH>
                      <TH>Error</TH>
                    </tr>
                  </thead>
                  <tbody>
                    {events.map(ev => (
                      <tr key={ev.id}>
                        <TD color={C.textSecondary}>{fmtTime(ev.created_at)}</TD>
                        <TD useMono color={
                          ev.action === 'buy' ? C.green :
                          ev.action === 'sell' ? C.red :
                          ev.action === 'close' ? C.amber :
                          C.textSecondary
                        }>
                          {(ev.action || '').toUpperCase()}
                        </TD>
                        <TD useMono>{ev.symbol || '--'}</TD>
                        <TD align="right" useMono>{ev.quantity || '--'}</TD>
                        <TD align="right" useMono>
                          {ev.price ? `$${Number(ev.price).toFixed(2)}` : '--'}
                        </TD>
                        <TD color={C.textSecondary}>{ev.strategy || '--'}</TD>
                        <TD useMono color={statusColor(ev.status)}>
                          {(ev.status || 'unknown').toUpperCase()}
                        </TD>
                        <TD color={C.red} style={{ maxWidth: 180, overflow: 'hidden', textOverflow: 'ellipsis' }}>
                          {ev.error || ''}
                        </TD>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            )}
          </GlassPanel>
        )}

        {/* ============================================================= */}
        {/* TEST TAB */}
        {/* ============================================================= */}
        {tab === 'test' && (
          <div>
            <GlassPanel className={s.mb20} style={{ padding: pad }}>
              <SectionHeader
                title="Test Webhook"
                sub="Simulate a TradingView webhook to verify your setup. This uses the test endpoint and does NOT execute real trades."
              />

              <div className={`${s.testFormGrid} ${isMobile ? s.testFormGridMobile : s.testFormGridDesktop}`}>
                {/* Action */}
                <div>
                  <label className={s.formLabel}>Action</label>
                  <select
                    value={testAction}
                    onChange={e => setTestAction(e.target.value)}
                    className={s.formSelect}
                  >
                    <option value="buy">buy</option>
                    <option value="sell">sell</option>
                    <option value="close">close</option>
                  </select>
                </div>

                {/* Symbol */}
                <div>
                  <label className={s.formLabel}>Symbol</label>
                  <input
                    type="text"
                    value={testSymbol}
                    onChange={e => setTestSymbol(e.target.value.toUpperCase())}
                    className={s.formInput}
                  />
                </div>

                {/* Price */}
                <div>
                  <label className={s.formLabel}>Price</label>
                  <input
                    type="number"
                    value={testPrice}
                    onChange={e => setTestPrice(e.target.value)}
                    step="0.01"
                    className={s.formInput}
                  />
                </div>

                {/* Quantity */}
                <div>
                  <label className={s.formLabel}>Quantity</label>
                  <input
                    type="number"
                    value={testQty}
                    onChange={e => setTestQty(e.target.value)}
                    className={s.formInput}
                  />
                </div>

                {/* Strategy */}
                <div>
                  <label className={s.formLabel}>Strategy</label>
                  <input
                    type="text"
                    value={testStrategy}
                    onChange={e => setTestStrategy(e.target.value)}
                    className={s.formInput}
                  />
                </div>

                {/* Timeframe */}
                <div>
                  <label className={s.formLabel}>Timeframe</label>
                  <input
                    type="text"
                    value={testTimeframe}
                    onChange={e => setTestTimeframe(e.target.value)}
                    className={s.formInput}
                  />
                </div>
              </div>

              <div className={s.testActions}>
                <PillBtn
                  label="Send Test Webhook"
                  onClick={handleTest}
                  loading={testing}
                  disabled={testing || !testSymbol}
                  color={C.purple}
                />
                <span className={s.testNote}>
                  Uses the /test endpoint (no real trade)
                </span>
              </div>
            </GlassPanel>

            {/* Test result */}
            <AnimatePresence>
              {testResult && (
                <motion.div
                  initial={{ opacity: 0, y: 10 }}
                  animate={{ opacity: 1, y: 0 }}
                  exit={{ opacity: 0, y: 10 }}
                >
                  <GlassPanel style={{ padding: pad }}>
                    <SectionHeader title="Test Result" />
                    <div className={`${s.testResultBox} ${testResult.valid ? s.testResultValid : s.testResultInvalid}`}>
                      <div className={s.testResultLabel} style={{ color: testResult.valid ? C.green : C.red }}>
                        {testResult.valid ? 'VALID' : 'INVALID'}
                      </div>
                      <div className={s.testResultMessage}>
                        {testResult.message}
                      </div>
                    </div>

                    {testResult.errors && testResult.errors.length > 0 && (
                      <div className={s.mb12}>
                        <div className={s.errorsLabel}>Errors</div>
                        {testResult.errors.map((err, i) => (
                          <div key={i} className={s.errorItem}>{err}</div>
                        ))}
                      </div>
                    )}

                    {testResult.parsed && (
                      <div>
                        <div className={s.parsedLabel}>Parsed Payload</div>
                        <CodeBlock
                          code={JSON.stringify(testResult.parsed, null, 2)}
                          isMobile={isMobile}
                        />
                      </div>
                    )}
                  </GlassPanel>
                </motion.div>
              )}
            </AnimatePresence>
          </div>
        )}
      </div>
    </AnimatedPage>
  );
}
